set -e; TIMESTAMP=$(date +%Y%m%d%H%M); sudo cp /boot/firmware/config.txt /boot/firmware/config.txt.$TIMESTAMP; sudo cp /boot/firmware/cmdline.txt /boot/firmware/cmdline.txt.$TIMESTAMP; if grep -q vc4-fkms-v3d /boot/firmware/config.txt; then sudo sed -i "s/vc4-fkms-v3d/vc4-kms-v3d/g" /boot/firmware/config.txt; elif ! grep -q vc4-kms-v3d /boot/firmware/config.txt; then echo "dtoverlay=vc4-kms-v3d" | sudo tee -a /boot/firmware/config.txt; fi; if ! grep -q consoleblank=0 /boot/firmware/cmdline.txt; then sudo sed -i "s/$/ consoleblank=0/" /boot/firmware/cmdline.txt; fi; echo "--- Resulting Config ---"; grep "vc4" /boot/firmware/config.txt; cat /boot/firmware/cmdline.txt; echo "--- Rebooting ---"; sudo reboot
